function merge(intervals) {
    if (intervals.length === 0) return [];
    let merged = [];
    let intervalsPairs = [];

    for (let i = 0; i < intervals.length; i += 2) {
        intervalsPairs.push([intervals[i], intervals[i + 1]]);
    }

    intervalsPairs.sort((a, b) => a[0] - b[0]);

    let currentInterval = intervalsPairs[0];

    for (let i = 1; i < intervalsPairs.length; i++) {
        if (currentInterval[1] >= intervalsPairs[i][0]) {
            currentInterval[1] = Math.max(currentInterval[1], intervalsPairs[i][1]);
        } else {
            merged.push(currentInterval);
            currentInterval = intervalsPairs[i];
        }
    }

    merged.push(currentInterval);
    return merged;
}

