    if (intervals[j][0] <= intervals[i][1]) {
        if (intervals[j][1] > intervals[i][1]) intervals[i][1] = intervals[j][1];
        for (int k = j; k < n-1; k++) intervals[k] = intervals[k+1];
        n--; j--;
    }
    *returnSize = n; *returnColumnSizes = colSizes; return intervals;
